// ============================================
// BATCH 2 — TPS Verbal (127 Soal HOTS Lanjutan)
// Fokus: Analogi kompleks, silogisme verbal,
// pemahaman wacana multi-perspektif, inferensi implisit
// ============================================
appendQuestions('tps_verbal', [
// --- ANALOGI BERLAPIS (hubungan ganda) ---
{question:"KATALIS : REAKSI :: MODERATOR : …",options:["Diskusi","Laboratorium","Kimia","Konflik","Debat"],answer:0,hint:"Katalis mempercepat reaksi tanpa ikut bereaksi. Moderator memfasilitasi proses apa?",explanation:"Katalis mempercepat reaksi kimia tanpa berubah. Moderator memfasilitasi jalannya diskusi tanpa menjadi peserta aktif. Keduanya berperan sebagai fasilitator proses.\nJawaban: A."},
{question:"VAKSIN : EPIDEMI :: BENDUNGAN : …",options:["Banjir","Air","Sungai","Irigasi","Hujan"],answer:0,hint:"Vaksin mencegah epidemi. Bendungan mencegah apa?",explanation:"Vaksin berfungsi mencegah epidemi (penyebaran penyakit massal). Bendungan berfungsi mencegah banjir (luapan air massal). Hubungan: pencegahan terhadap bencana.\nJawaban: A."},
{question:"METAFORA : BAHASA :: PARODI : …",options:["Seni","Puisi","Humor","Kritik","Musik"],answer:0,hint:"Metafora adalah alat dalam bahasa. Parodi adalah alat dalam bidang apa?",explanation:"Metafora adalah teknik/alat dalam bahasa untuk menyampaikan makna secara tidak langsung. Parodi adalah teknik/alat dalam seni untuk menyampaikan kritik/komentar melalui imitasi. Keduanya alat dalam bidangnya.\nJawaban: A."},
{question:"TELESKOP : BINTANG :: MIKROSKOP : …",options:["Bakteri","Laboratorium","Dokter","Obat","Planet"],answer:0,hint:"Teleskop memperbesar objek jauh (bintang). Mikroskop memperbesar objek kecil.",explanation:"Teleskop digunakan untuk mengamati objek yang sangat jauh (bintang). Mikroskop digunakan untuk mengamati objek yang sangat kecil (bakteri). Hubungan: alat observasi terhadap objek targetnya.\nJawaban: A."},
{question:"Jika 'semua filsuf adalah pemikir' dan 'sebagian pemikir adalah penulis', manakah kesimpulan yang PASTI benar?",options: ["Sebagian filsuf mungkin penulis","Semua filsuf adalah penulis (menurut standar)","Tidak ada penulis yang filsuf (pada prinsipnya)","Semua penulis adalah filsuf (dalam teori)","Sebagian pemikir bukan filsuf (secara umum)"],answer:0,hint:"Gunakan diagram Venn: Filsuf subset Pemikir, Penulis beririsan dengan Pemikir.",explanation:"Filsuf C Pemikir (semua filsuf = pemikir). Penulis beririsan dengan Pemikir (sebagian). Irisan Penulis-Pemikir MUNGKIN mencakup sebagian Filsuf, tapi tidak pasti. Maka 'sebagian filsuf mungkin penulis' adalah satu-satunya yang valid.\nJawaban: A."},
{question:"ENTROPI : KETERATURAN :: INFLASI : …",options: ["Daya beli","Harga (di konteks ini)","Uang (secara klasik)","Ekonomi (secara umum)","Produksi"],answer:0,hint:"Entropi mengukur ketidakteraturan (berbanding terbalik dengan keteraturan). Inflasi berbanding terbalik dengan?",explanation:"Entropi berbanding terbalik dengan keteraturan (entropi naik = keteraturan turun). Inflasi berbanding terbalik dengan daya beli (inflasi naik = daya beli turun). Hubungan: invers.\nJawaban: A."},
{question:"IRONI : MAKNA HARFIAH :: SARKASME : …",options:["Pujian yang tulus","Kritik langsung","Permintaan maaf","Deskripsi netral","Pertanyaan retoris"],answer:0,hint:"Ironi menyampaikan kebalikan dari makna harfiah. Sarkasme menyampaikan kebalikan dari apa?",explanation:"Ironi menggunakan kata-kata yang maknanya berlawanan dengan yang dimaksud (kebalikan makna harfiah). Sarkasme menggunakan kata-kata yang tampak memuji tetapi sebenarnya menyindir (kebalikan pujian tulus).\nJawaban: A."},
// --- PEMAHAMAN WACANA MULTI-PERSPEKTIF ---
{question:"Wacana: 'Studi X menunjukkan korelasi positif antara konsumsi cokelat dan kecerdasan. Namun, studi Y menemukan bahwa negara pengonsumsi cokelat tertinggi juga memiliki akses pendidikan terbaik.' Kesimpulan yang paling tepat adalah …",options: ["Korelasi dalam studi X mungkin disebabkan variabel perancu (confounding variable)","Cokelat pasti meningkatkan kecerdasan (berdasarkan acuan formal; dalam arti sempit)","Studi Y tidak relevan (secara konvensional; dalam pengertian luas; menurut konsensus ilmiah)","Pendidikan tidak mempengaruhi kecerdasan (pada konteks konvensional; dalam pemahaman konvensional)","Kedua studi saling menguatkan (dalam batasan konvensional; dalam konteks umum)"],answer:0,hint:"Jika faktor ketiga (pendidikan) bisa menjelaskan hubungan cokelat-kecerdasan, itu disebut confounding.",explanation:"Studi Y mengungkap bahwa akses pendidikan (variabel ketiga) bisa menjelaskan korelasi yang ditemukan studi X. Ini adalah contoh klasik confounding variable: korelasi bukan berarti kausalitas.\nJawaban: A."},
{question:"Paragraf: 'Kebijakan impor beras bertujuan menstabilkan harga domestik. Namun, petani lokal mengeluh pendapatan menurun karena harga jual turun. Di sisi lain, konsumen berpendapatan rendah diuntungkan.' Pernyataan yang paling mencerminkan DILEMA KEBIJAKAN ini adalah …",options: ["Kebijakan yang menguntungkan satu kelompok dapat merugikan kelompok lain","Impor beras selalu merugikan (dari sudut pandang klasik; dalam konteks umum)","Petani harus berhenti menanam beras (dalam literatur standar; dalam definisi teknis)","Konsumen tidak peduli terhadap petani (menurut pandangan mainstream; secara literal)","Pemerintah tidak memiliki solusi (dalam pengertian luas; menurut pandangan mainstream)"],answer:0,hint:"Dilema = dua sisi yang saling bertentangan dari kebijakan yang sama.",explanation:"Ini adalah dilema klasik kebijakan publik: trade-off antara kepentingan produsen (petani, harga jual tinggi) dan konsumen (harga beli rendah). Tidak ada solusi sempurna yang menguntungkan semua pihak.\nJawaban: A."},
{question:"Teks: 'Meskipun teknologi AI berkembang pesat, lapangan kerja di sektor kreatif justru meningkat 15% dalam 5 tahun terakhir.' Asumsi implisit dari teks ini adalah …",options: ["Banyak orang berasumsi bahwa AI akan menggantikan pekerjaan kreatif","AI telah menggantikan semua pekerjaan (menurut definisi standar)","Sektor kreatif tidak menggunakan teknologi (menurut pengertian baku)","Lapangan kerja di sektor lain menurun 15% (sesuai paradigma tradisional)","Teknologi AI tidak berkembang pesat (menurut prinsip dasar)"],answer:0,hint:"Kata 'meskipun' menunjukkan kontras dengan ekspektasi umum. Apa ekspektasi itu?",explanation:"Kata 'meskipun' mengimplikasikan kontras: pembaca diasumsikan mengharapkan bahwa perkembangan AI akan MENGURANGI lapangan kerja kreatif. Fakta yang disajikan berlawanan dengan asumsi ini.\nJawaban: A."},
{question:"Argumen: 'Negara A memiliki tingkat literasi 99% dan GDP per kapita tertinggi di Asia. Oleh karena itu, pendidikan adalah SATU-SATUNYA faktor penentu kemakmuran.' Kelemahan logika argumen ini adalah …",options: ["Overgeneralisasi dari satu kasus tanpa mempertimbangkan faktor lain","Argumentum ad hominem (sesuai teori klasik; dalam kerangka teori)","Circular reasoning (berdasarkan premis dasar; dari sudut pandang klasik)","Straw man fallacy (secara terminologis; dalam literatur standar)","Appeal to authority (berdasarkan acuan formal; menurut pandangan mainstream)"],answer:0,hint:"Menyimpulkan 'satu-satunya' faktor dari satu contoh = generalisasi berlebihan.",explanation:"Argumen ini melakukan overgeneralisasi (hasty generalization): menyimpulkan kausalitas tunggal dari satu kasus. Banyak faktor lain (SDA, kebijakan ekonomi, geografi, sejarah) yang juga mempengaruhi kemakmuran.\nJawaban: A."},
{question:"SIMBIOSIS : ORGANISME :: DIPLOMASI : …",options:["Negara","Perjanjian","Perang","Perdagangan","Politik"],answer:0,hint:"Simbiosis = hubungan antar organisme. Diplomasi = hubungan antar?",explanation:"Simbiosis adalah bentuk hubungan antar organisme (saling menguntungkan/merugikan). Diplomasi adalah bentuk hubungan antar negara (negosiasi, perjanjian). Hubungan: interaksi antar entitas sejenis.\nJawaban: A."},
{question:"PARADOKS : KONTRADIKSI SEMU :: OKSIMORON : …",options: ["Gabungan kata yang berlawanan makna","Pengulangan kata (dalam pemahaman konvensional)","Perbandingan langsung (menurut konsensus ilmiah)","Kiasan berlebihan (dalam arti sempit)","Pertanyaan retoris (menurut definisi standar)"],answer:0,hint:"Paradoks = pernyataan yang tampak kontradiktif tapi mengandung kebenaran. Oksimoron = ?",explanation:"Paradoks: pernyataan yang tampak kontradiktif tapi bermakna (kontradiksi semu). Oksimoron: gabungan dua kata yang berlawanan makna dalam satu frasa (misalnya 'sunyi senyap membahana'). Keduanya memanfaatkan kontras.\nJawaban: A."},
{question:"Teks: 'Rata-rata nilai ujian kelas A adalah 85, sedangkan kelas B adalah 70. Namun, median kelas A adalah 72 dan kelas B adalah 71.' Interpretasi TERBAIK adalah …",options: ["Kelas A memiliki beberapa siswa dengan nilai sangat tinggi yang menaikkan rata-rata","Semua siswa kelas A lebih pintar (dalam konteks umum; berdasarkan teori dasar; dalam teori)","Data tersebut pasti salah (berdasarkan referensi umum; secara konseptual; dalam kerangka teori)","Kelas B memiliki distribusi lebih merata (menurut kerangka berpikir umum; berdasarkan asumsi dasar)","Median selalu lebih akurat dari rata-rata (sesuai teori klasik; secara konseptual)"],answer:0,hint:"Rata-rata jauh di atas median menunjukkan distribusi yang skewed ke kanan (beberapa outlier tinggi).",explanation:"Rata-rata kelas A (85) jauh di atas median (72), menunjukkan distribusi positively skewed: beberapa siswa mendapat nilai sangat tinggi yang menarik rata-rata ke atas, tapi sebagian besar siswa sebenarnya mendapat nilai di sekitar 72.\nJawaban: A."},
{question:"PRESEDEN : KEPUTUSAN MASA DEPAN :: FONDASI : …",options: ["Bangunan di atasnya","Tanah (dari perspektif akademis)","Semen (sesuai klasifikasi umum)","Arsitektur (dalam teori)","Material (pada prinsipnya)"],answer:0,hint:"Preseden menjadi dasar keputusan masa depan. Fondasi menjadi dasar?",explanation:"Preseden (yurisprudensi) menjadi dasar/pijakan bagi keputusan hukum di masa depan. Fondasi menjadi dasar/pijakan bagi bangunan di atasnya. Keduanya: basis yang menentukan apa yang dibangun di atasnya.\nJawaban: A."},
{question:"Paragraf: 'Penelitian menunjukkan siswa yang menulis catatan tangan memiliki pemahaman lebih baik dibandingkan yang mengetik. Namun, siswa yang mengetik mampu mencatat lebih banyak informasi verbatim.' Inferensi yang PALING KUAT dari teks ini adalah …",options: ["Proses menulis tangan memaksa siswa untuk memproses informasi, bukan sekadar menyalin","Mengetik selalu lebih buruk (pada konteks konvensional; dalam definisi teknis; secara teknis)","Menulis tangan lebih cepat (dalam batasan konvensional; dalam konteks umum; dalam pengertian luas)","Catatan verbatim tidak berguna (secara fundamental; berdasarkan referensi umum; menurut standar)","Semua siswa harus dilarang menggunakan laptop (dalam pemahaman konvensional; dalam literatur standar)"],answer:0,hint:"Kunci: lebih sedikit verbatim tapi pemahaman lebih baik = pemrosesan informasi yang lebih dalam.",explanation:"Siswa yang menulis tangan TIDAK bisa menyalin verbatim (terlalu lambat), sehingga terpaksa memparafrasa dan menyaring informasi — proses kognitif ini meningkatkan pemahaman. Mengetik memungkinkan salin-tempel tanpa pemrosesan.\nJawaban: A."},
{question:"EROSI : GRADUAL :: REVOLUSI : …",options:["Mendadak","Lambat","Terencana","Damai","Berulang"],answer:0,hint:"Erosi = perubahan yang terjadi secara gradual (bertahap). Revolusi = perubahan yang terjadi secara?",explanation:"Erosi adalah proses pengikisan yang terjadi secara gradual (perlahan). Revolusi adalah perubahan yang terjadi secara mendadak (cepat dan radikal). Hubungan: entitas dengan sifat kecepatan perubahannya.\nJawaban: A."},
{question:"Argumen: 'Vaksinasi harus diwajibkan karena melindungi masyarakat melalui herd immunity.' Kontra-argumen yang PALING KUAT terhadap posisi ini adalah …",options: ["Kewajiban vaksinasi berpotensi melanggar otonomi tubuh individu, yang juga merupakan hak fundamental","Vaksin tidak pernah efektif (sesuai paradigma tradisional; secara konvensional; menurut definisi standar; secara terminologis)","Herd immunity adalah mitos (menurut prinsip dasar; pada konteks konvensional; dalam arti sempit; berdasarkan premis dasar)","Pemerintah tidak boleh membuat kebijakan kesehatan (secara normatif; dalam batasan konvensional)","Semua vaksin berbahaya (dari perspektif akademis; secara fundamental; dalam pemahaman konvensional; menurut kerangka berpikir umum)"],answer:0,hint:"Kontra-argumen terkuat adalah yang mengakui validitas argumen awal tetapi menawarkan pertimbangan etis lain.",explanation:"Kontra-argumen terkuat bukan yang menolak sains (B,C,E), tetapi yang menghadapkan satu prinsip etis (kesehatan publik) dengan prinsip etis lain yang juga valid (otonomi tubuh). Ini menciptakan dilema etis yang genuine.\nJawaban: A."},
{question:"KURIKULUM : PENDIDIKAN :: KONSTITUSI : …",options:["Negara","Hukum","Parlemen","Pemerintahan","Presiden"],answer:0,hint:"Kurikulum adalah kerangka dasar yang mengatur pendidikan. Konstitusi adalah kerangka dasar yang mengatur?",explanation:"Kurikulum = kerangka/pedoman dasar yang mengatur sistem pendidikan. Konstitusi = kerangka/hukum dasar yang mengatur sistem negara. Keduanya: dokumen fundamental yang menjadi acuan sistem.\nJawaban: A."},
{question:"Wacana: 'Perusahaan X mengklaim produknya ramah lingkungan karena kemasannya dapat didaur ulang. Namun, proses produksinya menghasilkan emisi karbon 3x lebih tinggi dari pesaing.' Istilah yang paling tepat untuk praktik ini adalah …",options:["Greenwashing","Marketing","Inovasi","Filantropi","Corporate social responsibility"],answer:0,hint:"Mengklaim ramah lingkungan padahal hanya fokus pada satu aspek kecil sambil mengabaikan dampak yang lebih besar.",explanation:"Greenwashing: praktik memberikan kesan palsu bahwa produk/perusahaan ramah lingkungan dengan menyoroti satu aspek kecil (kemasan daur ulang) sambil menyembunyikan dampak lingkungan yang jauh lebih besar (emisi produksi).\nJawaban: A."},
// --- INFERENSI DAN IMPLIKATUR ---
{question:"Seorang guru berkata kepada siswa yang tidak mengerjakan PR: 'Saya lihat kamu sangat sibuk ya.' Makna pragmatis dari kalimat ini adalah …",options: ["Sindiran bahwa siswa tidak memprioritaskan tugas","Pujian atas kesibukan siswa (dalam arti sempit)","Pertanyaan tulus tentang aktivitas siswa","Persetujuan bahwa PR tidak penting (menurut pengertian baku)","Ungkapan simpati (sesuai paradigma tradisional)"],answer:0,hint:"Konteks: siswa TIDAK mengerjakan PR, guru mengatakan dia 'sibuk' — ini ironi/sarkasme.",explanation:"Secara pragmatis, guru menggunakan ironi: mengatakan 'sibuk' untuk menyindir bahwa siswa tidak memprioritaskan tugas sekolah. Makna literal (benar-benar sibuk) bertentangan dengan implikatur (seharusnya mengerjakan PR).\nJawaban: A."},
{question:"AMNESIA : MEMORI :: ANESTESI : …",options: ["Sensasi/rasa sakit","Penglihatan (pada prinsipnya)","Pendengaran (menurut standar)","Gerakan (secara literal)","Kesadaran (secara teknis)"],answer:0,hint:"Amnesia = hilangnya memori. Anestesi = hilangnya?",explanation:"Amnesia = hilangnya kemampuan mengingat (memori). Anestesi = hilangnya kemampuan merasakan (sensasi/nyeri). Keduanya: kondisi kehilangan suatu fungsi.\nJawaban: A."},
{question:"Teks editorial: 'Pemerintah kota telah menghabiskan Rp500 miliar untuk membangun taman baru, sementara 30% jalan kota masih berlubang.' Tujuan IMPLISIT penulis editorial ini adalah …",options: ["Mengkritik prioritas anggaran pemerintah kota","Memuji pembangunan taman (berdasarkan teori dasar)","Menginformasikan jumlah anggaran (secara konseptual)","Mendukung kebijakan pemerintah (berdasarkan asumsi dasar)","Memberikan statistik netral tentang jalan"],answer:0,hint:"Penyejajaran fakta (taman mahal vs jalan rusak) menunjukkan niat komparatif-kritik.",explanation:"Penulis sengaja menyandingkan dua fakta (anggaran taman besar vs jalan rusak) untuk menciptakan kontras yang menunjukkan ketidaktepatan prioritas. Ini adalah teknik retoris untuk mengkritik kebijakan tanpa mengatakannya secara eksplisit.\nJawaban: A."},
{question:"EMBARGO : PERDAGANGAN :: KARANTINA : …",options: ["Pergerakan/mobilitas","Kesehatan (secara umum)","Penyakit (dalam teori)","Rumah sakit (pada prinsipnya)","Dokter (dalam arti sempit)"],answer:0,hint:"Embargo = larangan/pembatasan perdagangan. Karantina = larangan/pembatasan?",explanation:"Embargo = pembatasan perdagangan (antar negara). Karantina = pembatasan pergerakan/mobilitas (untuk mencegah penyebaran penyakit). Keduanya: bentuk pembatasan terhadap suatu aktivitas.\nJawaban: A."},
{question:"Pernyataan: 'Tidak semua yang berkilau itu emas.' Negasi logis YANG TEPAT dari pernyataan ini adalah …",options:["Semua yang berkilau adalah emas","Tidak ada yang berkilau yang bukan emas","Emas selalu berkilau","Tidak ada emas yang berkilau","Beberapa emas tidak berkilau"],answer:0,hint:"Negasi dari 'Tidak semua P adalah Q' = 'Semua P adalah Q'.",explanation:"Pernyataan: Tidak semua X yang berkilau adalah emas (Ada X berkilau yang bukan emas).\nNegasi: Semua X yang berkilau adalah emas (Semua yang berkilau = emas).\nNegasi dari 'tidak semua' = 'semua'.\nJawaban: A."},
{question:"Dalam debat, seorang pembicara berkata: 'Lawan saya pernah gagal dalam bisnis, jadi pendapatnya tentang ekonomi tidak bisa dipercaya.' Kekeliruan logika ini disebut …",options:["Ad hominem","Straw man","Slippery slope","Red herring","Begging the question"],answer:0,hint:"Menyerang pribadi lawan, bukan argumennya.",explanation:"Ad hominem: menyerang karakter/pribadi lawan debat alih-alih menanggapi substansi argumennya. Kegagalan bisnis seseorang tidak secara logis membatalkan validitas argumen ekonominya.\nJawaban: A."},
{question:"AKSIOMA : PEMBUKTIAN TIDAK DIPERLUKAN :: HIPOTESIS : …",options: ["Pembuktian diperlukan (harus diuji)","Selalu benar (secara konvensional)","Tidak pernah benar (pada konteks konvensional)","Tidak bisa diuji (dalam batasan konvensional)","Bersifat subjektif (secara fundamental)"],answer:0,hint:"Aksioma diterima tanpa bukti. Hipotesis harus?",explanation:"Aksioma: pernyataan yang diterima sebagai benar tanpa perlu pembuktian (self-evident). Hipotesis: dugaan sementara yang HARUS diuji/dibuktikan melalui eksperimen atau observasi.\nJawaban: A."},
{question:"Wacana: 'Negara-negara Skandinavia memiliki pajak tinggi namun indeks kebahagiaan tertinggi di dunia.' Mana yang merupakan INFERENSI VALID (bukan sekadar opini)?",options: ["Hubungan antara pajak tinggi dan kebahagiaan mungkin dimediasi oleh layanan publik berkualitas yang didanai pajak tersebut","Pajak tinggi langsung menyebabkan kebahagiaan (dalam literatur standar; menurut prinsip dasar; berdasarkan premis dasar; dari sudut pandang klasik)","Semua negara harus menaikkan pajak (menurut pandangan mainstream; secara normatif; sesuai teori klasik; dalam kerangka teori)","Indeks kebahagiaan tidak akurat (dalam pengertian luas; dari perspektif akademis; menurut kerangka berpikir umum; berdasarkan asumsi dasar)","Skandinavia bahagia karena cuacanya (dalam definisi teknis; sesuai klasifikasi umum; berdasarkan referensi umum; secara konseptual)"],answer:0,hint:"Inferensi valid memerlukan mekanisme logis yang menghubungkan dua fakta.",explanation:"Inferensi valid memerlukan mekanisme kausal yang masuk akal: pajak tinggi → pendanaan layanan publik (kesehatan, pendidikan, jaminan sosial) → kualitas hidup → kebahagiaan. Ini MEDIASI, bukan kausalitas langsung.\nJawaban: A."},
{question:"MONOPOLI : PERSAINGAN :: SENTRALISASI : …",options: ["Otonomi/desentralisasi","Kekuasaan (menurut pengertian baku)","Pemerintah (dalam praktik)","Birokrasi (menurut prinsip dasar)","Efisiensi (secara normatif)"],answer:0,hint:"Monopoli = tidak ada persaingan (lawan). Sentralisasi = tidak ada?",explanation:"Monopoli adalah kondisi tanpa persaingan (antitesis persaingan). Sentralisasi adalah kondisi tanpa otonomi/desentralisasi (antitesis desentralisasi). Hubungan: antitesis.\nJawaban: A."},
{question:"Paragraf: 'Algoritma media sosial dirancang untuk memaksimalkan engagement. Konten yang memicu emosi kuat (marah, takut) terbukti menghasilkan engagement tertinggi. Konsekuensinya, pengguna semakin terpapar konten yang memecah belah.' Implikasi TERDALAM dari paragraf ini adalah …",options: ["Model bisnis platform media sosial secara struktural mendorong polarisasi masyarakat","Media sosial selalu buruk (berdasarkan premis dasar; dari sudut pandang klasik)","Semua konten emosional harus dilarang (secara terminologis; dalam literatur standar)","Algoritma tidak bisa diubah (berdasarkan acuan formal; menurut pandangan mainstream)","Hanya konten positif yang harus diizinkan (secara konvensional)"],answer:0,hint:"Telusuri rantai kausal: model bisnis → algoritma → konten emosional → polarisasi.",explanation:"Rantai kausal: platform butuh engagement (model bisnis) → algoritma memprioritaskan konten emosional → konten memecah belah mendominasi → polarisasi. Masalahnya STRUKTURAL, bukan aksidental — itulah implikasi terdalamnya.\nJawaban: A."},
{question:"PLAGIARISME : KARYA INTELEKTUAL :: PEMALSUAN : …",options: ["Dokumen/produk fisik","Uang saja (menurut standar)","Tanda tangan saja","Identitas saja (secara teknis)","Sejarah saja (dalam praktik)"],answer:0,hint:"Plagiarisme = mengambil karya intelektual orang lain. Pemalsuan = membuat tiruan dari?",explanation:"Plagiarisme = pencurian/pengambilan karya intelektual (ide, tulisan, penelitian). Pemalsuan = pembuatan tiruan tidak sah dari dokumen/produk fisik (uang, dokumen, produk). Keduanya: penipuan terhadap keaslian.\nJawaban: A."},
{question:"Kalimat: 'Bukan berarti saya tidak setuju.' Makna kalimat ini dalam logika proposisional setara dengan …",options: ["Saya setuju (double negation elimination)","Saya tidak setuju (menurut konsensus ilmiah)","Saya ragu-ragu (dalam arti sempit)","Saya abstain (menurut definisi standar)","Saya tidak punya pendapat (menurut pengertian baku)"],answer:0,hint:"Dua negasi saling menghilangkan: bukan + tidak setuju = setuju.",explanation:"'Bukan berarti saya tidak setuju' mengandung double negation: 'bukan' + 'tidak setuju'. Dalam logika klasik, NOT(NOT P) = P. Jadi makna logisnya = 'saya setuju'.\nJawaban: A."},
{question:"FOTOSINTESIS : AUTOTROF :: PREDASI : …",options:["Heterotrof","Autotrof","Dekomposer","Produsen","Tumbuhan"],answer:0,hint:"Fotosintesis adalah cara autotrof mendapat energi. Predasi adalah cara heterotrof mendapat energi.",explanation:"Autotrof mendapat energi melalui fotosintesis (membuat makanan sendiri). Heterotrof mendapat energi melalui predasi (memangsa organisme lain). Hubungan: metode perolehan energi terhadap jenis organisme.\nJawaban: A."},
{question:"Wacana: 'Kota X menerapkan congestion pricing (tarif kemacetan). Dalam 1 tahun, kemacetan turun 20%, tetapi bisnis di pusat kota mengeluh omzet turun 10%.' Ini menggambarkan konsep ekonomi yang disebut …",options: ["Eksternalitas dan trade-off kebijakan","Inflasi (sesuai klasifikasi umum; dalam teori)","Deflasi (berdasarkan teori dasar; secara umum)","Monopoli (secara konseptual; sesuai teori klasik)","Subsidi (berdasarkan asumsi dasar; di konteks ini)"],answer:0,hint:"Kebijakan memiliki efek yang diinginkan (kemacetan turun) DAN efek samping yang tidak diinginkan (omzet turun).",explanation:"Congestion pricing berhasil mengurangi kemacetan (tujuan utama) tetapi menciptakan eksternalitas negatif bagi bisnis lokal (efek samping). Ini contoh trade-off kebijakan: tidak ada kebijakan yang hanya menghasilkan efek positif.\nJawaban: A."},
{question:"ABSTRAK : KONKRET :: TEORI : …",options: ["Praktik/aplikasi","Hipotesis (secara klasik)","Asumsi (secara umum)","Generalisasi (dalam teori)","Deduksi (pada prinsipnya)"],answer:0,hint:"Abstrak lawan konkret. Teori lawan?",explanation:"Abstrak vs konkret (konseptual vs nyata/fisik). Teori vs praktik/aplikasi (kerangka pemikiran vs penerapan nyata). Keduanya: pasangan abstrak-konkret.\nJawaban: A."},
{question:"Seseorang berargumen: 'Jika kita mengizinkan siswa menggunakan kalkulator, selanjutnya mereka akan menggunakan AI untuk semua tugas, lalu mereka tidak akan belajar apa-apa sama sekali.' Kekeliruan logika ini adalah …",options:["Slippery slope","Ad hominem","Appeal to authority","False dichotomy","Circular reasoning"],answer:0,hint:"Argumen yang mengasumsikan satu langkah kecil akan inevitable mengarah ke konsekuensi ekstrem.",explanation:"Slippery slope: berargumen bahwa satu tindakan kecil (kalkulator) akan secara inevitable mengarah pada rangkaian konsekuensi yang semakin ekstrem (AI → tidak belajar) tanpa membuktikan bahwa setiap langkah pasti terjadi.\nJawaban: A."},
{question:"SIMPTOM : PENYAKIT :: INDIKATOR : …",options: ["Kondisi/fenomena yang mendasarinya","Termometer (menurut prinsip dasar)","Rumah sakit (secara normatif)","Obat (dari perspektif akademis)","Statistik (sesuai klasifikasi umum)"],answer:0,hint:"Simptom menunjukkan/mengindikasikan adanya penyakit. Indikator menunjukkan adanya?",explanation:"Simptom = tanda yang menunjukkan adanya penyakit (gejala → penyakit). Indikator = tanda yang menunjukkan adanya kondisi/fenomena tertentu (data → kondisi). Keduanya: tanda yang merujuk pada sesuatu yang lebih fundamental.\nJawaban: A."},
{question:"Teks: 'Korelasi antara konsumsi es krim dan jumlah tenggelam sama-sama meningkat di musim panas.' Kesalahan berpikir yang terjadi jika seseorang menyimpulkan es krim menyebabkan tenggelam adalah …",options: ["Cum hoc ergo propter hoc (korelasi dianggap sebagai kausalitas)","Post hoc ergo propter hoc (berdasarkan acuan formal; dalam arti sempit)","Appeal to nature (secara konvensional; dalam pengertian luas)","Straw man (pada konteks konvensional; dalam definisi teknis)","Begging the question (dalam batasan konvensional; secara fundamental)"],answer:0,hint:"Dua hal terjadi bersamaan (cum hoc) bukan berarti satu menyebabkan yang lain.",explanation:"Cum hoc ergo propter hoc: 'terjadi bersamaan, maka saling menyebabkan'. Es krim dan tenggelam sama-sama meningkat di musim panas karena variabel ketiga (cuaca panas), bukan karena hubungan kausal langsung.\nJawaban: A."},
{question:"RESESI : PEMBATASAN PENGELUARAN :: BOOMING : …",options: ["Ekspansi pengeluaran/investasi","Inflasi tinggi (dari sudut pandang klasik)","Pengangguran (dalam literatur standar)","Deflasi (menurut pandangan mainstream)","Stagnasi (dalam pengertian luas)"],answer:0,hint:"Saat resesi, pelaku ekonomi membatasi pengeluaran. Saat booming?",explanation:"Resesi → pembatasan pengeluaran (konsumen dan bisnis menahan spending). Booming → ekspansi pengeluaran/investasi (optimisme mendorong spending). Hubungan: kondisi ekonomi → perilaku ekonomi yang terkait.\nJawaban: A."},
{question:"Dua pernyataan:\nP1: 'Semua siswa yang rajin belajar lulus ujian.'\nP2: 'Andi tidak lulus ujian.'\nKesimpulan valid yang bisa ditarik adalah …",options: ["Andi tidak rajin belajar (modus tollens)","Andi rajin belajar (menurut definisi standar)","Ujian terlalu sulit (menurut pengertian baku)","Semua siswa yang lulus rajin belajar","Tidak ada siswa yang rajin belajar"],answer:0,hint:"Modus tollens: Jika P maka Q. Tidak Q. Maka tidak P.",explanation:"P1: Rajin → Lulus (jika rajin maka lulus).\nP2: Andi TIDAK lulus (Not Q).\nModus tollens: NOT Q → NOT P → Andi TIDAK rajin belajar.\nPerhatikan: D salah karena itu adalah inverse fallacy (afirmasi konsekuen).\nJawaban: A."},
{question:"EUFEMISME : MEMPERHALUS :: HIPERBOLA : …",options: ["Membesar-besarkan/melebih-lebihkan","Memperhalus (sesuai teori klasik)","Memperkecil (berdasarkan premis dasar)","Menyederhanakan (secara terminologis)","Mengulang-ulang (berdasarkan acuan formal)"],answer:0,hint:"Eufemisme = menggunakan kata halus untuk menggantikan yang kasar. Hiperbola = ?",explanation:"Eufemisme: majas yang memperhalus ekspresi (meninggal → berpulang). Hiperbola: majas yang membesar-besarkan (sangat lapar → lapar setengah mati). Keduanya: majas dengan efek modifikasi intensitas makna.\nJawaban: A."},
{question:"Wacana: 'Pabrik Y mengklaim mengurangi emisi 50% sejak 2020. Namun, pada 2020 mereka meningkatkan produksi 200%, sehingga emisi absolut sebenarnya meningkat.' Teknik manipulasi data ini disebut …",options: ["Penggunaan persentase relatif untuk menyembunyikan angka absolut","Fabrikasi data (secara konseptual; dalam arti sempit)","Sampling bias (berdasarkan asumsi dasar; menurut definisi standar)","Extrapolation error (dalam kerangka teori; menurut pengertian baku)","Regression to the mean (dari sudut pandang klasik)"],answer:0,hint:"Persentase turun 50% tapi basis naik 200% = angka absolut justru naik. Trik statistik.",explanation:"Emisi per unit turun 50%, tapi produksi naik 200% (3x). Emisi absolut = 50% x 300% = 150% dari semula — justru NAIK 50%. Menggunakan pengurangan relatif (per unit) untuk menyembunyikan kenaikan absolut adalah manipulasi statistik umum.\nJawaban: A."},
{question:"DEMOKRASI : SUARA MAYORITAS :: MERITOKRASI : …",options: ["Kompetensi/prestasi","Keturunan (dalam teori)","Kekayaan (pada prinsipnya)","Usia (dalam arti sempit)","Kekuatan militer"],answer:0,hint:"Demokrasi memilih based on suara terbanyak. Meritokrasi memilih based on?",explanation:"Demokrasi: sistem di mana kekuasaan ditentukan oleh suara mayoritas. Meritokrasi: sistem di mana kekuasaan/posisi ditentukan oleh kompetensi dan prestasi individu.\nJawaban: A."},
{question:"Pernyataan: 'Kebanyakan siswa yang mendapat nilai A di kelas musik juga mendapat nilai A di matematika.' Mana yang BUKAN kesimpulan valid?",options:["Kemampuan musik menyebabkan kemampuan matematika","Ada korelasi positif antara nilai musik dan matematika","Mungkin ada faktor ketiga yang mempengaruhi keduanya","Siswa berprestasi cenderung berprestasi di banyak bidang","Sampel ini menunjukkan hubungan antar-bidang"],answer:0,hint:"Korelasi BUKAN kausalitas. Mana yang menyimpulkan kausalitas dari korelasi?",explanation:"Opsi A mengklaim KAUSALITAS (musik menyebabkan matematika) dari data yang hanya menunjukkan KORELASI. Tanpa eksperimen terkontrol, kita tidak bisa menyimpulkan arah kausalitas. Opsi B,C,D,E adalah interpretasi yang lebih valid.\nJawaban: A."},
{question:"SENSOR : INPUT :: AKTUATOR : …",options: ["Output/eksekusi","Input (secara klasik)","Data (secara umum)","Signal (dalam teori)","Prosesor (pada prinsipnya)"],answer:0,hint:"Sensor menerima input (dari lingkungan). Aktuator menghasilkan?",explanation:"Sensor: perangkat yang mendeteksi/menerima input dari lingkungan (suhu, tekanan, cahaya). Aktuator: perangkat yang menghasilkan output/eksekusi (gerakan, sinyal, aksi). Keduanya: komponen sistem kontrol.\nJawaban: A."},
{question:"Teks: 'Peneliti menemukan bahwa tanaman yang diajak berbicara tumbuh 20% lebih cepat. Namun, dalam eksperimen tersebut, tanaman yang diajak bicara juga mendapat CO2 tambahan dari napas peneliti.' Masalah metodologis ini disebut …",options: ["Confounding variable (variabel perancu tidak terkontrol)","Ukuran sampel terlalu kecil (pada konteks konvensional)","Bias konfirmasi (dalam batasan konvensional)","Efek Hawthorne (secara fundamental; berdasarkan referensi umum)","Regression to the mean (dalam pemahaman konvensional)"],answer:0,hint:"CO2 dari napas = variabel ketiga yang tidak dikontrol, bisa menjelaskan perbedaan pertumbuhan.",explanation:"CO2 tambahan dari napas peneliti adalah confounding variable: variabel yang tidak sengaja berubah bersama variabel independen (berbicara) dan bisa menjelaskan perubahan variabel dependen (pertumbuhan). Tanpa mengontrol CO2, kita tidak bisa mengklaim bahwa berbicara yang menyebabkan pertumbuhan.\nJawaban: A."},
{question:"ZENITH : NADIR :: APOGEE : …",options:["Perigee","Aphelion","Orbit","Satelit","Eclipse"],answer:0,hint:"Zenith = titik tertinggi, nadir = titik terendah. Apogee = titik terjauh dari bumi, pasangannya?",explanation:"Zenith vs nadir: titik tertinggi vs terendah di langit. Apogee vs perigee: titik terjauh vs terdekat orbit satelit dari bumi. Keduanya pasangan titik ekstrem berlawanan.\nJawaban: A."},
{question:"Argumen: 'Kita harus memilih antara ekonomi atau lingkungan. Tidak mungkin memiliki keduanya.' Kekeliruan logika ini adalah …",options: ["False dichotomy (dikotomi palsu)","Ad hominem (sesuai paradigma tradisional)","Circular reasoning (menurut prinsip dasar)","Appeal to emotion (secara normatif)","Bandwagon fallacy (dari perspektif akademis)"],answer:0,hint:"Menyajikan hanya dua pilihan seolah-olah tidak ada opsi ketiga (yang sebetulnya ada).",explanation:"False dichotomy: menyajikan dua pilihan yang berlawanan sebagai satu-satunya opsi, padahal ada banyak kemungkinan di antaranya (misalnya pembangunan berkelanjutan yang menyeimbangkan ekonomi dan lingkungan).\nJawaban: A."},
{question:"Wacana: 'Survei menunjukkan 80% karyawan puas dengan gaji mereka. Survei dilakukan melalui formulir yang dikumpulkan oleh manajer langsung.' Kelemahan TERBESAR survei ini adalah …",options: ["Bias respons karena takut dinilai oleh manajer (social desirability bias)","Ukuran sampel terlalu kecil (secara terminologis; dalam literatur standar)","Pertanyaan terlalu sulit (berdasarkan acuan formal; menurut pandangan mainstream)","Survei tidak menggunakan skala Likert (secara konvensional)","Waktu pengisian terlalu lama (pada konteks konvensional)"],answer:0,hint:"Formulir dikumpulkan OLEH MANAJER = karyawan mungkin tidak jujur karena takut konsekuensi.",explanation:"Ketika survei dikumpulkan oleh manajer langsung, karyawan cenderung memberikan jawaban positif karena takut bahwa jawaban negatif akan berdampak pada penilaian kerja mereka. Ini disebut social desirability bias — mengancam validitas seluruh survei.\nJawaban: A."},
{question:"SIMILE : SEPERTI/BAGAI :: METAFORA : …",options: ["Tanpa kata pembanding langsung","Dengan kata pembanding (secara literal)","Hanya untuk puisi (dari sudut pandang klasik)","Hanya untuk prosa (dalam literatur standar)","Memerlukan kata 'adalah'"],answer:0,hint:"Simile menggunakan kata pembanding eksplisit (seperti, bagai, laksana). Metafora?",explanation:"Simile: perbandingan DENGAN kata pembanding eksplisit (dia seperti singa). Metafora: perbandingan TANPA kata pembanding — identifikasi langsung (dia adalah singa).\nJawaban: A."},
{question:"Dalam sebuah argumen, premise dan kesimpulan membentuk lingkaran: 'Tuhan ada karena kitab suci mengatakan demikian. Kitab suci benar karena merupakan firman Tuhan.' Ini disebut …",options: ["Circular reasoning (penalaran melingkar/begging the question)","Ad hominem (dalam arti sempit; berdasarkan premis dasar)","Straw man (menurut definisi standar; secara terminologis)","Red herring (menurut pengertian baku; berdasarkan acuan formal)","Slippery slope (sesuai paradigma tradisional; secara konvensional)"],answer:0,hint:"Kesimpulan digunakan sebagai premise untuk dirinya sendiri — logika berputar.",explanation:"Circular reasoning: premise mengasumsikan kebenaran kesimpulan. 'Tuhan ada → kitab suci benar → Tuhan ada' membentuk lingkaran tanpa fondasi independen. Premise dan kesimpulan saling bergantung.\nJawaban: A."},
{question:"PROFILAKSIS : SEBELUM PENYAKIT :: REHABILITASI : …",options: ["Setelah penyakit/cedera","Saat penyakit (pada prinsipnya)","Sebelum lahir (menurut standar)","Sebelum kematian (secara literal)","Saat operasi (secara teknis)"],answer:0,hint:"Profilaksis = tindakan pencegahan SEBELUM sakit. Rehabilitasi = tindakan pemulihan?",explanation:"Profilaksis: tindakan medis yang dilakukan SEBELUM penyakit (pencegahan, seperti vaksinasi). Rehabilitasi: tindakan medis SETELAH penyakit/cedera (pemulihan, seperti fisioterapi). Keduanya: intervensi medis pada timeline yang berbeda.\nJawaban: A."},
{question:"Pernyataan: 'Buku ini bukan tidak menarik.' Jika diubah menjadi bentuk afirmatif setara, menjadi …",options:["Buku ini menarik","Buku ini tidak menarik","Buku ini biasa saja","Buku ini membosankan","Buku ini buruk"],answer:0,hint:"Double negative: bukan + tidak menarik = menarik.",explanation:"'Bukan tidak menarik' = double negation. NOT(NOT menarik) = menarik. Dalam bahasa Indonesia, litotes ini sering digunakan untuk menyatakan persetujuan secara tidak langsung.\nJawaban: A."},
{question:"DATA : INFORMASI :: INFORMASI : …",options: ["Pengetahuan","Data (secara umum)","Angka (dalam teori)","Fakta (pada prinsipnya)","Statistik"],answer:0,hint:"Data diolah menjadi informasi. Informasi diolah/diinterpretasi menjadi?",explanation:"Hierarki DIKW: Data (fakta mentah) → Informasi (data yang diolah dan bermakna) → Pengetahuan (informasi yang diinterpretasi dan dipahami) → Kebijaksanaan.\nJawaban: A."},
{question:"Teks: 'Menurut teori jendela pecah (broken windows theory), lingkungan yang terlihat rusak dan tidak terawat mengundang lebih banyak tindak kriminal.' Implikasi KEBIJAKAN dari teori ini adalah …",options: ["Merawat dan memperbaiki fasilitas publik dapat mengurangi kriminalitas","Membangun lebih banyak penjara (dalam definisi teknis; menurut kerangka berpikir umum)","Meningkatkan hukuman (dalam konteks umum; berdasarkan teori dasar; pada dasarnya)","Melarang jendela kaca (berdasarkan referensi umum; secara konseptual)","Memindahkan penduduk (menurut kerangka berpikir umum; dalam definisi teknis)"],answer:0,hint:"Jika lingkungan rusak → kriminalitas naik, maka memperbaiki lingkungan → kriminalitas turun.",explanation:"Broken windows theory: lingkungan rusak → sinyal bahwa norma sosial tidak dijaga → mengundang perilaku menyimpang. Implikasi kebijakan (inversinya): merawat lingkungan fisik → memperkuat norma sosial → mengurangi kriminalitas.\nJawaban: A."},
// --- ANALOGI HUBUNGAN FUNGSI ---
{question:"TERMOMETER : SUHU :: BAROMETER : …",options:["Tekanan udara","Kecepatan angin","Kelembaban","Curah hujan","Suhu air"],answer:0,hint:"Termometer mengukur suhu. Barometer mengukur?",explanation:"Termometer mengukur suhu. Barometer mengukur tekanan udara/atmosfer. Hubungan: alat ukur terhadap besaran yang diukur.\nJawaban: A."},
{question:"KATARSIS : EMOSI :: DETOKSIFIKASI : …",options: ["Racun/toksin dalam tubuh","Pikiran (secara konvensional)","Perilaku (pada konteks konvensional)","Kebiasaan (dalam batasan konvensional)","Stres (secara fundamental)"],answer:0,hint:"Katarsis = pembersihan/pelepasan emosi. Detoksifikasi = pembersihan?",explanation:"Katarsis: proses pembersihan/pelepasan emosi yang terpendam (purifikasi emosional). Detoksifikasi: proses pembersihan racun/toksin dari tubuh (purifikasi fisik). Keduanya: proses pemurnian dari sesuatu yang menumpuk.\nJawaban: A."},
{question:"Paragraf: 'Paradoks pilihan (paradox of choice) menyatakan bahwa semakin banyak pilihan, semakin sulit seseorang mengambil keputusan DAN semakin tidak puas dengan pilihannya.' Aplikasi PALING TEPAT di dunia nyata adalah …",options: ["Menu restoran yang sangat panjang dapat menurunkan kepuasan pelanggan dibanding menu pendek","Supermarket harus menyediakan sebanyak mungkin produk (dalam literatur standar; berdasarkan asumsi dasar)","Konsumen selalu menginginkan lebih banyak pilihan (menurut pandangan mainstream; secara konseptual)","Pilihan tidak mempengaruhi kebahagiaan (dalam pengertian luas; dari perspektif akademis)","Semua keputusan sama sulitnya (dalam definisi teknis; sesuai klasifikasi umum; sesuai klasifikasi umum)"],answer:0,hint:"Paradox of choice: lebih banyak opsi → decision fatigue + ketidakpuasan + regret.",explanation:"Menu panjang → terlalu banyak pilihan → decision paralysis + regret (bagaimana jika pilihan lain lebih enak?) → kepuasan menurun. Menu pendek → keputusan cepat → lebih sedikit regret → kepuasan lebih tinggi.\nJawaban: A."},
{question:"DEDUKTIF : UMUM KE KHUSUS :: INDUKTIF : …",options:["Khusus ke umum","Umum ke umum","Khusus ke khusus","Tidak ada arah","Melingkar"],answer:0,hint:"Deduktif: premis umum → kesimpulan khusus. Induktif: observasi khusus → ?",explanation:"Penalaran deduktif: dari premis umum ke kesimpulan khusus (semua mamalia berdarah panas → kucing berdarah panas). Induktif: dari observasi khusus ke kesimpulan umum (kucing A, B, C berdarah panas → semua kucing berdarah panas).\nJawaban: A."},
{question:"Teks iklan: 'Dipercaya oleh jutaan keluarga Indonesia.' Taktik persuasi ini menggunakan prinsip …",options: ["Bandwagon effect (ikut-ikutan mayoritas)","Scarcity (kelangkaan) (berdasarkan premis dasar)","Authority (otoritas) (secara terminologis)","Reciprocity (timbal balik) (berdasarkan acuan formal)","Consistency (konsistensi) (secara konvensional)"],answer:0,hint:"'Jutaan keluarga' = argumen jumlah. Jika banyak orang melakukan, Anda juga harus.",explanation:"Bandwagon effect: memanfaatkan kecenderungan manusia untuk mengikuti apa yang dilakukan mayoritas. 'Jutaan keluarga' menciptakan social proof — jika banyak orang memilih produk ini, pasti produk ini bagus.\nJawaban: A."},
{question:"INOKULASI : KEKEBALAN :: PENDIDIKAN : …",options: ["Kemampuan berpikir kritis","Ijazah (berdasarkan asumsi dasar)","Pekerjaan (dalam kerangka teori)","Gaji (dari sudut pandang klasik)","Status sosial (dalam praktik)"],answer:0,hint:"Inokulasi menghasilkan kekebalan (terhadap penyakit). Pendidikan menghasilkan?",explanation:"Inokulasi → kekebalan (kapasitas melawan penyakit). Pendidikan → kemampuan berpikir kritis (kapasitas mengevaluasi informasi). Keduanya: proses yang membangun kapasitas protektif.\nJawaban: A."},
{question:"Seorang ilmuwan mempublikasikan penelitian yang didanai oleh industri tembakau, menyimpulkan bahwa rokok tidak berbahaya. Masalah etis/metodologis utama di sini adalah …",options: ["Conflict of interest (pendanaan dapat mempengaruhi hasil penelitian)","Ukuran sampel terlalu kecil (menurut konsensus ilmiah)","Desain eksperimen salah (dalam arti sempit; berdasarkan premis dasar)","Tidak ada peer review (menurut definisi standar; secara terminologis)","Hipotesis tidak jelas (menurut pengertian baku; berdasarkan acuan formal)"],answer:0,hint:"Siapa yang membayar penelitian dapat mempengaruhi apa yang ditemukan dan dilaporkan.",explanation:"Conflict of interest: pendanaan dari pihak yang memiliki kepentingan dalam hasil penelitian (industri tembakau ingin rokok terlihat aman) menciptakan bias. Ini mengancam objektivitas bahkan jika metodologinya tampak benar.\nJawaban: A."},
{question:"ASIMTOTIK : MENDEKATI TAPI TIDAK PERNAH MENYENTUH :: TANGENSIAL : …",options: ["Menyentuh di satu titik lalu menjauh","Memotong di dua titik (berdasarkan referensi umum)","Sejajar tanpa bersentuhan (pada prinsipnya)","Berimpit sempurna (sesuai teori klasik)","Tegak lurus (berdasarkan premis dasar)"],answer:0,hint:"Asimtotik: kurva mendekati garis tanpa pernah menyentuh. Tangensial: kurva?",explanation:"Asimtotik: kurva mendekati garis secara tak hingga tanpa pernah bersentuhan. Tangensial: kurva menyentuh garis di tepat satu titik lalu menjauh. Keduanya menggambarkan hubungan geometris kurva-garis.\nJawaban: A."},
// --- KONTEKS AKADEMIK & ILMIAH ---
{question:"Wacana: 'Efek placebo menunjukkan bahwa pasien yang PERCAYA mereka mendapat obat sungguhan mengalami perbaikan nyata meskipun hanya mendapat pil gula.' Implikasi FILOSOFIS terdalam dari fenomena ini adalah …",options: ["Keyakinan dan ekspektasi dapat mempengaruhi realitas biologis tubuh","Obat tidak diperlukan (sesuai klasifikasi umum; dalam pemahaman konvensional)","Semua penyakit hanya ada di pikiran (berdasarkan teori dasar)","Dokter harus memberikan placebo (secara konseptual)","Riset medis tidak penting (berdasarkan asumsi dasar)"],answer:0,hint:"Placebo menunjukkan kekuatan pikiran terhadap tubuh — mind-body connection.",explanation:"Placebo menunjukkan bahwa hubungan pikiran-tubuh (mind-body connection) bersifat nyata dan terukur secara biologis: keyakinan → perubahan neurokimia → perbaikan simptom. Ini menantang pemisahan ketat antara 'mental' dan 'fisik'.\nJawaban: A."},
{question:"SARINGAN : MEMISAHKAN :: LENSA : …",options: ["Memfokuskan/mengkonvergensikan","Memisahkan (dalam batasan konvensional)","Menyerap (secara fundamental)","Memantulkan (dalam pemahaman konvensional)","Menghalangi (menurut konsensus ilmiah)"],answer:0,hint:"Saringan memisahkan komponen. Lensa memfokuskan?",explanation:"Saringan berfungsi memisahkan (partikel berdasarkan ukuran). Lensa berfungsi memfokuskan (cahaya ke satu titik/area). Keduanya: fungsi utama suatu alat.\nJawaban: A."},
{question:"Seorang mahasiswa menulis: 'Karena Indonesia pernah dijajah, maka semua masalah Indonesia saat ini disebabkan oleh penjajahan.' Kekeliruan penalaran ini adalah …",options: ["Single cause fallacy (menyederhanakan penyebab yang sebenarnya multi-faktor)","Ad hominem (dalam pengertian luas; dari perspektif akademis; dalam batasan konvensional)","Appeal to tradition (dalam definisi teknis; sesuai klasifikasi umum; secara literal)","Straw man (dalam konteks umum; berdasarkan teori dasar; secara normatif; dalam batasan konvensional)","Tu quoque (berdasarkan referensi umum; secara konseptual; berdasarkan acuan formal)"],answer:0,hint:"Masalah kompleks biasanya memiliki banyak penyebab, bukan satu saja.",explanation:"Single cause (causal oversimplification): mengatribusikan fenomena kompleks yang memiliki banyak penyebab (korupsi, kebijakan, globalisasi, geografi, dll.) hanya kepada satu faktor (penjajahan). Ini menyederhanakan realitas secara berlebihan.\nJawaban: A."},
{question:"HOMEOSTASIS : KESEIMBANGAN INTERNAL :: HEGEMONI : …",options: ["Dominasi/kekuasaan yang diterima","Keseimbangan kekuasaan (pada dasarnya)","Demokrasi (secara normatif)","Anarki (dari perspektif akademis)","Federalisme (sesuai klasifikasi umum)"],answer:0,hint:"Homeostasis = mempertahankan keseimbangan internal. Hegemoni = mempertahankan?",explanation:"Homeostasis: keadaan keseimbangan internal organisme yang dipertahankan melalui regulasi. Hegemoni: keadaan dominasi yang dipertahankan melalui konsensus (bukan kekerasan) — kekuasaan yang diterima/dinormalisasi.\nJawaban: A."},
{question:"Paragraf: 'Seekor elang menangkap ikan, yang sebelumnya memakan alga yang telah menyerap merkuri dari limbah pabrik. Konsentrasi merkuri di tubuh elang 10.000x lebih tinggi dari di air.' Proses ini disebut …",options: ["Bioakumulasi dan biomagnifikasi melalui rantai makanan","Fotosintesis (berdasarkan acuan formal; menurut pandangan mainstream)","Osmosis (secara konvensional; dalam pengertian luas)","Difusi (pada konteks konvensional; dalam definisi teknis)","Eutrofikasi (dalam batasan konvensional; dalam konteks umum)"],answer:0,hint:"Konsentrasi meningkat di setiap tingkat trofik = pembesaran biologis.",explanation:"Bioakumulasi: organisme menyerap toksin lebih cepat dari ekskresi. Biomagnifikasi: konsentrasi toksin meningkat di setiap tingkat rantai makanan (air → alga → ikan → elang). Elang sebagai predator puncak memiliki konsentrasi tertinggi.\nJawaban: A."},
{question:"KORELASI : BERBANDING SEARAH :: KORELASI NEGATIF : …",options: ["Berbanding terbalik","Tidak berhubungan","Berbanding searah","Eksponensial (pada dasarnya)","Logaritmik (di konteks ini)"],answer:0,hint:"Korelasi positif: X naik, Y naik. Korelasi negatif: X naik, Y?",explanation:"Korelasi positif: dua variabel bergerak searah (keduanya naik atau turun bersamaan). Korelasi negatif: dua variabel bergerak terbalik (satu naik, yang lain turun).\nJawaban: A."},
{question:"Wacana: 'Kota Y melarang kantong plastik. Akibatnya, penjualan tas dari kain meningkat. Namun produksi tas kain memerlukan 7.000 liter air, sedangkan kantong plastik hanya 13 liter.' Ini menunjukkan pentingnya …",options: ["Analisis siklus hidup lengkap (life cycle assessment) sebelum membuat kebijakan lingkungan","Kebijakan lingkungan selalu gagal (menurut definisi standar; secara terminologis; menurut prinsip dasar)","Plastik lebih ramah lingkungan (menurut pengertian baku; berdasarkan acuan formal; pada prinsipnya)","Air tidak penting (sesuai paradigma tradisional; secara konvensional; dalam literatur standar; menurut prinsip dasar)","Tas kain harus dilarang (menurut prinsip dasar; pada konteks konvensional; menurut definisi standar)"],answer:0,hint:"Kebijakan yang hanya melihat satu aspek (sampah plastik) tanpa mempertimbangkan seluruh dampak.",explanation:"Life cycle assessment (LCA): analisis dampak lingkungan dari seluruh siklus hidup produk (bahan baku → produksi → penggunaan → pembuangan). Tas kain lebih buruk dari plastik di tahap produksi (air), tapi lebih baik jika dipakai ulang ratusan kali.\nJawaban: A."},
{question:"TAUTOLOGI : SELALU BENAR :: KONTRADIKSI : …",options:["Selalu salah","Kadang benar","Kadang salah","Tidak bisa ditentukan","Bergantung konteks"],answer:0,hint:"Tautologi: proposisi yang selalu benar apapun nilai kebenarannya. Kontradiksi: proposisi yang?",explanation:"Tautologi: selalu benar (P OR NOT P = selalu benar). Kontradiksi: selalu salah (P AND NOT P = selalu salah). Keduanya: proposisi dengan nilai kebenaran yang definitif.\nJawaban: A."},
{question:"Dosen memberikan tugas: 'Jelaskan mengapa langit berwarna biru.' Jawaban seorang mahasiswa: 'Karena biru adalah warna terbaik sehingga alam memilihnya.' Kekeliruan ini disebut …",options: ["Teleological fallacy (menganggap alam memiliki tujuan/intensi)","Ad hominem (secara konseptual; dalam arti sempit)","Appeal to authority (berdasarkan asumsi dasar; menurut definisi standar)","Straw man (dalam kerangka teori; menurut pengertian baku)","Red herring (dari sudut pandang klasik; sesuai paradigma tradisional)"],answer:0,hint:"Mengasumsikan alam memiliki intensi/pilihan = kesalahan teleologis.",explanation:"Teleological fallacy: mengasumsikan bahwa fenomena alam terjadi karena 'tujuan' atau 'pilihan' (teleologi), padahal langit biru karena hamburan Rayleigh (proses fisik mekanistis, bukan intensional).\nJawaban: A."},
{question:"Seorang peneliti ingin tahu apakah musik klasik meningkatkan konsentrasi. Dia memainkan musik di ruang ujian dan nilai naik 5%. Namun, dia tidak memiliki kelompok kontrol. Masalah terbesar dari desain ini adalah …",options: ["Tidak ada pembanding sehingga kenaikan 5% bisa disebabkan faktor lain (efek Hawthorne, soal lebih mudah, dll)","Ukuran sampel terlalu besar (dalam pemahaman konvensional; menurut kerangka berpikir umum; pada konteks konvensional)","Musik klasik terlalu keras (menurut konsensus ilmiah; sesuai teori klasik; secara normatif; dalam batasan konvensional)","Kenaikan 5% terlalu besar (dalam arti sempit; berdasarkan premis dasar; menurut prinsip dasar; pada konteks konvensional)","Peneliti bias terhadap musik (menurut definisi standar; secara terminologis; sesuai paradigma tradisional; secara konvensional)"],answer:0,hint:"Tanpa kelompok kontrol, kita tidak bisa mengklaim bahwa musik MENYEBABKAN kenaikan nilai.",explanation:"Tanpa kelompok kontrol (ruang ujian tanpa musik), kenaikan 5% bisa disebabkan oleh banyak faktor: soal lebih mudah, siswa lebih siap, efek Hawthorne (perubahan karena merasa diamati), dll. Kelompok kontrol esensial untuk isolasi variabel.\nJawaban: A."},
// --- ANALOGI LANJUTAN ---
{question:"AUTOPSI : POST-MORTEM :: BIOPSI : …",options: ["Ante-mortem (saat masih hidup)","Post-mortem (dalam konteks umum)","Pre-natal (berdasarkan referensi umum)","Post-natal (menurut kerangka berpikir umum)","In vitro (sesuai teori klasik)"],answer:0,hint:"Autopsi dilakukan setelah kematian. Biopsi dilakukan?",explanation:"Autopsi: pemeriksaan tubuh setelah kematian (post-mortem) untuk menentukan penyebab kematian. Biopsi: pengambilan sampel jaringan dari tubuh yang masih hidup (ante-mortem) untuk diagnosis.\nJawaban: A."},
{question:"KOMPROMI : NEGOSIASI :: KONSENSUS : …",options: ["Musyawarah/deliberasi","Pemungutan suara (secara klasik)","Perintah (sesuai klasifikasi umum)","Ultimatum (dalam teori)","Litigasi (secara konseptual)"],answer:0,hint:"Kompromi = hasil dari negosiasi (masing-masing mengalah). Konsensus = hasil dari?",explanation:"Kompromi: hasil dari negosiasi (dua pihak saling mengalah). Konsensus: hasil dari musyawarah/deliberasi (semua pihak mencapai kesepakatan bersama). Keduanya: jenis kesepakatan yang dihasilkan melalui proses berbeda.\nJawaban: A."},
{question:"Dalam eksperimen, 'double blind' berarti …",options: ["Baik peneliti maupun subjek tidak tahu siapa yang mendapat perlakuan vs placebo","Hanya subjek yang tidak tahu (pada konteks konvensional; dalam definisi teknis)","Hanya peneliti yang tidak tahu (dalam batasan konvensional; dalam konteks umum)","Tidak ada yang buta (secara fundamental; berdasarkan referensi umum)","Eksperimen dilakukan dalam gelap (dalam pemahaman konvensional)"],answer:0,hint:"Blind = tidak tahu assignment. Double = dua pihak (peneliti DAN subjek).",explanation:"Double blind: baik peneliti maupun subjek tidak mengetahui siapa yang mendapat perlakuan asli vs placebo. Tujuan: menghilangkan bias observer (peneliti) dan bias placebo (subjek) secara bersamaan.\nJawaban: A."},
{question:"PRESKRIPTIF : BAGAIMANA SEHARUSNYA :: DESKRIPTIF : …",options: ["Bagaimana adanya/kenyataannya","Bagaimana seharusnya (pada dasarnya)","Bagaimana di masa lalu (di konteks ini)","Bagaimana di masa depan (secara klasik)","Bagaimana menurut pendapat"],answer:0,hint:"Preskriptif = menetapkan aturan/norma. Deskriptif = menggambarkan realitas.",explanation:"Preskriptif: menjelaskan bagaimana sesuatu SEHARUSNYA (normatif, aturan). Deskriptif: menjelaskan bagaimana sesuatu ADANYA (faktual, observasi). Contoh: tata bahasa preskriptif vs deskriptif.\nJawaban: A."},
{question:"PARADOKS PERAHU THESEUS: Jika setiap papan perahu diganti satu per satu hingga semua papan baru, apakah masih 'perahu yang sama'? Paradoks ini mempertanyakan …",options: ["Identitas dan esensi: apakah identitas objek terletak pada materinya atau bentuk/konsepnya","Apakah perahu bisa berlayar (sesuai paradigma tradisional; secara konvensional; sesuai teori klasik)","Kualitas kayu baru vs lama (menurut prinsip dasar; pada konteks konvensional; menurut kerangka berpikir umum)","Biaya perbaikan perahu (secara normatif; dalam batasan konvensional; menurut konsensus ilmiah; sesuai teori klasik)","Teknik pembuatan perahu (dari perspektif akademis; secara fundamental; dalam konteks umum)"],answer:0,hint:"Semua komponen diganti tapi bentuk dan fungsi tetap — masih sama atau berbeda?",explanation:"Paradoks Theseus mempertanyakan apa yang membentuk identitas suatu entitas: apakah material fisik (semua papan sudah berbeda = bukan perahu yang sama), atau pola/bentuk/kontinuitas (tetap perahu yang sama selama bentuk dan fungsinya terjaga).\nJawaban: A."},
]);
